<?php require_once __DIR__.'/bootstrap.php'; $message=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $email=trim($_POST['email']??''); $token=bin2hex(random_bytes(24)); try{ $stmt=Database::conn()->prepare("SELECT id FROM users WHERE email=? LIMIT 1"); $stmt->execute([$email]); if($u=$stmt->fetch()){ Database::conn()->prepare("INSERT INTO password_resets (user_id, token, expires_at, created_at) VALUES (?,?,DATE_ADD(NOW(),INTERVAL 1 HOUR),NOW())")->execute([$u['id'],$token]); $message='Reset token created. For now, check phpMyAdmin password_resets table for token.'; } else $message='If the email exists, a reset will be created.'; }catch(Throwable $e){ error_log($e->getMessage()); $message='Reset system unavailable.'; }} ?><!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><link rel="stylesheet" href="/server/admin/assets/css/app.css"></head><body class="login-page"><div class="login-card"><h1>Forgot Password</h1><?php if($message):?><div class="alert"><?=htmlspecialchars($message)?></div><?php endif;?><form method="post"><div class="field"><label>Email</label><input class="input" type="email" name="email" required></div><button class="btn">Create Reset Token</button></form><p><a href="/server/admin/login.php">Back to login</a></p></div></body></html>
